    12→    @Dependency(\.notificationManager) private var notificationManager
    13→
    14→    func getTimer() -> TimerEntity? {
    15→        return userDefaults.getTimer()
    16→    }
    17→    
    18→    func saveTimerAndSchedulePush(_ newTimer: TimerEntity) {
    19→        userDefaults.setTimer(newTimer)
    20→        notificationManager.schedulePush(for: newTimer)
    21→    }
    22→
    23→    func removeTimer() {
    24→        notificationManager.removeAndCancelPush()
    25→        userDefaults.removeTimer()
    26→    }
