//  Created by suyeon on 3/7/25.
//

import ComposableArchitecture
import Foundation

@Reducer
struct AppSettingFeature {
    @ObservableState
    struct State: Equatable {
        struct ToggleSliderSection: Equatable {
            var type: SettingType
            var title: String
            var description: String? = nil
            var icon: String? = nil
            var currentSliderScale: CGFloat
            var lastSliderScale: CGFloat
            var sliderLowerBound: CGFloat = 0
            var isOn: Bool
        }

        var sections: [SettingType: ToggleSliderSection] = [:]
    }

    enum Action {
        case onLoaded
        case backButtonTapped
        case sliderDragChanged(SettingType, CGFloat)
        case sliderDragEnded(SettingType)
        case onToggle(SettingType, Bool)
    }

    @Dependency(\.userDefaults) private var userDefaults
    @Dependency(\.dismiss) var dismiss

    var body: some ReducerOf<Self> {
        Reduce<State, Action> { state, action in
            switch action {
            case .onLoaded:
                // 초기값 설정
                let haptic = CGFloat(userDefaults.getSettingSliderScale(for: .haptic))
                let isHapticOn = userDefaults.isSettingToggleOn(for: .haptic)

                state.sections[.haptic] = .init(type: .haptic, title: "진동 설정", icon: "icon_haptic", currentSliderScale: haptic, lastSliderScale: haptic, sliderLowerBound: 0.05, isOn: isHapticOn)

                let volume = CGFloat(userDefaults.getSettingSliderScale(for: .volume))
                let isVolumeOn = userDefaults.isSettingToggleOn(for: .volume)

                state.sections[.volume] = .init(type: .volume, title: "소리 설정", description: "앱 내 사운드만 조정하며, 푸시 알림 소리는 변경되지 않습니다.", icon: "icon_volume", currentSliderScale: volume, lastSliderScale: volume, sliderLowerBound: 0.05, isOn: isVolumeOn)

                return .none

            case .backButtonTapped:
                return .run { _ in
                    await self.dismiss()
                }

            case let .sliderDragChanged(type, sliderValue):
                state.sections[type]?.currentSliderScale = sliderValue
                return .none
            case let .sliderDragEnded(type):
                if let currentScale = state.sections[type]?.currentSliderScale {
                    state.sections[type]?.lastSliderScale = currentScale

                    userDefaults.setSettingSliderScale(for: type, value: Float(currentScale))
                }
                return .none

            case let .onToggle(type, isOn):
                state.sections[type]?.isOn = isOn
                state.sections[type]?.currentSliderScale = isOn ? 0.5 : 0.0
                state.sections[type]?.lastSliderScale = isOn ? 0.5 : 0.0
                userDefaults.setSettingToggle(for: type, to: isOn)
                userDefaults.setSettingSliderScale(for: type, value: isOn ? 0.5 : 0.0)
                return .none
            }
        }
    }
}

