//
//  AppSettingView.swift
//  ggaebiz
//
//  Created by suyeon on 3/7/25.
//

import SwiftUI
import ComposableArchitecture

struct AppSettingView: View {
    @Perception.Bindable private var store: StoreOf<AppSettingFeature>

    var body: some View {
        WithPerceptionTracking {
            VStack(spacing: 0) {
                NavigationTitleView(title: "설정") {
                    store.send(.backButtonTapped)
                }

                VStack(spacing: 0) {
                    Color.clear
                        .frame(height: 21)

                    if let hapticData = store.sections[.haptic] {
                        toggleSliderSection(data: hapticData)
                            .padding(.bottom, 20)
                    }

                    if let volumeData = store.sections[.volume] {
                        toggleSliderSection(data: volumeData)
                    }

                    Spacer()
                }

            }
            .navigationBarBackButtonHidden(true)
            .padding(.horizontal, 20)
            .background(.coolGray25)
            .onLoad {
                store.send(.onLoaded)
            }
        }
    }

    init(store: StoreOf<AppSettingFeature>) {
        self.store = store
    }
}

private extension AppSettingView {
    func toggleSliderSection(data: AppSettingFeature.State.ToggleSliderSection) -> some View {
        let iconSize = 16.0
        let iconBackgroundColor: Color = .coolGray50
        let iconCornerRadius = 14.0
        let textColor: Color = .coolGray800

        return VStack(spacing: 0) {
            HStack(spacing: 0) {
                if let icon = data.icon {
                    Image(icon)
                        .resizable()
                        .frame(width: iconSize, height: iconSize)
                        .padding(.all, 8)
                        .background(iconBackgroundColor)
                        .cornerRadius(iconCornerRadius)
                        .padding(.trailing, 8)
                }

                Text(data.title)
                    .pretendardFont(weight: .semiBold600, size: 16)
                    .foregroundStyle(textColor)
                    .frame(maxWidth: .infinity, alignment: .leading)
                    .padding(.trailing, 12)

                toggleSwitch(type: data.type, isOn: data.isOn)
            }
            .padding(.vertical, 10)

            if data.isOn {
                VStack(spacing: 10) {
                    if let desc = data.description {
                        Text(desc)
                            .pretendardFont(weight: .medium500, size: 12)
                            .foregroundStyle(.coolGray400)
                            .frame(maxWidth: .infinity, alignment: .leading)
                            .padding(.leading, 4)
                            .padding(.vertical, 2)
                    }
                    ZStack {
                        slider(type: data.type, currentScale: data.currentSliderScale, lastScale: data.lastSliderScale, lowerBound: data.sliderLowerBound)
                            .padding(.horizontal, 16)
                            .padding(.vertical, 15)
                    }
                    .background(.coolGray50)
                    .cornerRadius(16)
                    .padding(.top, 8)
                }
            }
        }
    }

    func toggleSwitch(type: SettingType, isOn: Bool) -> some View {
        let onColor: Color = .coolGray900
        let offColor: Color = .coolGray75

        return ZStack(alignment: isOn ? .trailing : .leading) {
            RoundedRectangle(cornerRadius: 16)
                .frame(width: 52, height: 32)
                .foregroundColor(isOn ? onColor : offColor)

            Circle()
                .frame(width: 24, height: 24)
                .padding(.horizontal, 4)
                .foregroundColor(.white)
        }
        .onTapGesture {
            store.send(.onToggle(type, !isOn), animation: .easeOut(duration: 0.3))
        }
    }

    func slider(type: SettingType, currentScale: CGFloat, lastScale: CGFloat, lowerBound: CGFloat = 0) -> some View {
        let sliderWidth = UIScreen.main.bounds.width - 20 * 2 - 16 * 2

        return WithPerceptionTracking {
            SliderView(width: sliderWidth,
                       currentValue: currentScale * sliderWidth,
                       onDragChanged: { v, values in
                let changedValue: Double
                let lastValue = lastScale * sliderWidth

                if v.translation.width > 0 {
                    changedValue = min(values.last ?? 0, lastValue + v.translation.width)
                } else {
                    changedValue = max(lowerBound * sliderWidth, lastValue + v.translation.width)
                }

                store.send(.sliderDragChanged(type, changedValue/sliderWidth))
            },
                       onDragEnded: { _, _ in
                store.send(.sliderDragEnded(type))
            })
        }
    }
}

