import SwiftUI

import ComposableArchitecture

struct MainView: View {
    private struct Constants {
        static let buttonString = "%@랑 타이머 설정하기"
        static let backgroundColor: Color = .coolGray25
        static let guideBackgroundColor: Color = .black.opacity(0.8)
        static let avatarHighlightSize: CGFloat = 240.0
    }

    @Perception.Bindable private var store: StoreOf<MainFeature>
    @State private var commonTitleButtonTopOffset: CGFloat = .zero
    @State private var avatarScrollViewBottomYOffset: CGFloat = .zero

    init(store: StoreOf<MainFeature>) {
        self.store = store
    }

    var body: some View {
        WithPerceptionTracking {
            NavigationStack(
                path: $store.scope(state: \.path, action: \.path)
            ) {
                VStack(spacing: 0) {
                    titleAndSettingButtonView

                    AvatarBubbleView(text: store.currentAvatarType.mainMessage)
                        .padding(.bottom, 23)
                        .padding(.horizontal, 20)
                        .dimmedIfNeeded(
                            shouldDimmed: store.showGuide,
                            shouldHighlight: store.currentGuideType == .previewOnTouch
                        )

                    avatarSelectorView

                    AvatarNameView(text: "\(store.currentAvatarType.englishName) \(store.currentAvatarType.name)")
                        .padding(.bottom, 16)
                        .dimmedIfNeeded(shouldDimmed: store.showGuide)

                    TagListView(avatarType: store.currentAvatarType)
                        .padding(.horizontal, 20)
                        .padding(.bottom, 44)
                        .dimmedIfNeeded(shouldDimmed: store.showGuide)

                    DotSelectorView(count: store.avatarList.count, currentIndex: store.currentIndex) { idx in
                        store.send(.avatarSelectorDotTapped(idx))
                    }
                    .dimmedIfNeeded(shouldDimmed: store.showGuide)

                    Spacer()
                        .frame(minHeight: 73.0)
                        .dimmedIfNeeded(shouldDimmed: store.showGuide)

                    CTAButton(text: String(format: Constants.buttonString, store.currentAvatarType.name), type: .dark) {
                        store.send(.timerSettingButtonTapped)
                    }
                    .padding(.bottom, 20)
                    .padding(.horizontal, 20)
                    .dimmedIfNeeded(shouldDimmed: store.showGuide)
                }
                .wrapScrollIfNeeded()
                .disabled(store.showGuide)
                .background(Constants.backgroundColor)
                .overlay {
                    if store.showGuide {
                        guideView
                    }
                }

            } destination: { childStore in
                WithPerceptionTracking {
                    switch childStore.state {
                    case .timerSetting:
                        if let childStore = childStore.scope(
                            state: \.timerSetting,
                            action: \.timerSetting
                        ) {
                            TimerSettingView(store: childStore, avatarType: store.currentAvatarType)
                        }

                    case .appSetting:
                        if let childStore = childStore.scope(
                            state: \.appSetting,
                            action: \.appSetting
                        ) {
                            AppSettingView(store: childStore)
                        }

                    case .camera:
                        if let childStore = childStore.scope(
                            state: \.camera,
                            action: \.camera
                        ) {
                            CameraView(store: childStore)
                        }

                    case .gallery:
                        if let childStore = childStore.scope(
                            state: \.gallery,
                            action: \.gallery
                        ) {
                            GalleryView(store: childStore)
                        }

                    case .snapshotEdit:
                        if let childStore = childStore.scope(
                            state: \.snapshotEdit,
                            action: \.snapshotEdit
                        ) {
                            SnapshotEditView(store: childStore)
                        }
                    case .snapshotShare:
                        if let childStore = childStore.scope(
                            state: \.snapshotShare,
                            action: \.snapshotShare
                        ) {
                            SnapshotShareView(store: childStore)
                        }
                    case .summaryCard:
                        if let childStore = childStore.scope(
                            state: \.summaryCard,
                            action: \.summaryCard
                        ) {
                            SummaryCardView(store: childStore)
                        }
                    }
                }
            }
            .fullScreenCover(
                item: $store.scope(
                    state: \.destination?.timerOnProgress,
                    action: \.destination.timerOnProgress
                ),
                content: { store in
                    TimerOnProgressView(store: store)
                }
            )
            .fullScreenCover(
                item: $store.scope(
                    state: \.destination?.timerEnd,
                    action: \.destination.timerEnd
                ),
                content: { store in
                    TimerEndView(store: store)
                }
            )
            .onLoad {
                store.send(.onLoad)
            }
            .onChange(of: store.path.isEmpty) { isEmpty in
                if isEmpty {
                    store.send(.snapshotPathBecameEmpty)
                }
            }
            .toast(
                toast: $store.toast,
                hasCTAButton: true
            )
            .customAlert(isPresented: $store.showSnapshotAlert) {
                snapshotStartAlertView
            }
            .customAlert(isPresented: $store.showSnapshotTypeAlert) {
                snapshotTypeAlertView()
            }
        }
    }
}

struct AvatarNameView: View {
    private struct Constants {
        static let textFont: Font = .pretendard(.bold700, size: 20)
        static let textColor: Color = .coolGray800
    }

    let text: String

    var body: some View {
        Text(text)
            .font(Constants.textFont)
            .foregroundStyle(Constants.textColor)
            .frame(maxWidth: .greatestFiniteMagnitude)
            .padding(.horizontal, 16)
            .padding(.vertical, 6)
    }
}

private extension MainView {
    @ViewBuilder
    var titleAndSettingButtonView: some View {
        ZStack {
            CommonTitleButtonView {
                store.send(.appSettingButtonTapped)
            }
            .padding(.bottom, 58)
            .dimmedIfNeeded(shouldDimmed: store.showGuide)

            if store.showGuide {
                Text("\(store.currentGuideType.rawValue + 1)/\(MainFeature.GuideType.allCases.count)")
                    .pretendardFont(weight: .semiBold600, size: 16.0)
                    .foregroundStyle(.white)
                    .padding(.bottom, 58)
            }
        }
        .background(
            GeometryReader(content: { proxy in
                Color.clear
                    .onLoad {
                        commonTitleButtonTopOffset = proxy.frame(in: .global).minY
                    }
            })
        )
    }

    @ViewBuilder
    var avatarSelectorView: some View {
        if store.showGuide {
            ZStack {
                if store.currentGuideType == .previewOnTouch {
                    Constants.guideBackgroundColor

                    RoundedRectangle(cornerRadius: 30.0)
                        .fill(Constants.backgroundColor)
                        .frame(width: Constants.avatarHighlightSize, height: Constants.avatarHighlightSize)

                    RoundedRectangle(cornerRadius: 30.0)
                        .stroke(
                            .orange400,
                            style: StrokeStyle(
                                lineWidth: 3.0,
                                lineCap: .round,
                                dash: [14, 8]
                            )
                        )
                        .frame(width: Constants.avatarHighlightSize, height: Constants.avatarHighlightSize)
                }

                avatarScrollView
                    .dimmedIfNeeded(shouldDimmed: store.currentGuideType != .previewOnTouch)
                    .disabled(true)
            }
            .zIndex(1)
        } else {
            avatarScrollView
        }
    }

    var avatarScrollView: some View {
        struct Constants {
            static let itemWidth: CGFloat = 240
            static let itemHeight: CGFloat = 240
            static let screenWidth: CGFloat = UIScreen.main.bounds.width
            static let spacing: CGFloat = (Constants.screenWidth - Constants.itemWidth * 1.5)/2
        }

        return ScrollView(.horizontal) {
            HStack(spacing: Constants.spacing) {
                    Color.clear
                    .frame(width: (Constants.screenWidth - Constants.itemWidth)/2 - Constants.spacing)

                ForEach(0..<store.avatarImages.count, id: \.self) { idx in
                    WithPerceptionTracking {
                        Button {
                            store.send(.avatarTapped)
                        } label: {
                            store.avatarImages[idx]
                                .resizable()
                                .frame(width: Constants.itemWidth)
                                .scaleEffect(store.isAvatarTapped && store.currentIndex == idx ? 0.9 : 1.0)
                                .animation(.linear(duration: 0.2), value: store.isAvatarTapped)
                        }
                    }
                }
            }
            .offset(x: CGFloat(-(store.currentIndex)) * (Constants.itemWidth + Constants.spacing) + store.selectorViewOffset)
                .animation(.easeOut, value: store.currentIndex)
                .highPriorityGesture(
                    DragGesture()
                        .onChanged { value in
                            store.send(.avatarSelectorDragChanged(min(value.translation.width, Constants.itemWidth + Constants.spacing)))
                        }
                        .onEnded { value in
                            var newIdx = store.currentIndex
                            newIdx -= Int(value.predictedEndTranslation.width) > 0 ? 1 : -1
                            newIdx = max(0, min(newIdx, store.avatarImages.count-1))

                            store.send(.avatarSelectorDragEnded(newIdx))
                        }
                )
            .frame(height: Constants.itemHeight)
        }
        .scrollDisabled(true)
        .background(
            GeometryReader(content: { proxy in
                Color.clear
                    .onLoad {
                        avatarScrollViewBottomYOffset = proxy.frame(in: .global).maxY
                    }
            })
        )
    }
}

// guide 관련
private extension MainView {
    @ViewBuilder
    var guideView: some View {
        let type = store.currentGuideType

        VStack(spacing: .zero) {
            switch type {
            case .previewOnTouch:
                Spacer()
                    .frame(height: avatarScrollViewBottomYOffset - commonTitleButtonTopOffset)
            case .turnOffSilentMode:
                Spacer()
                    .frame(height: UIScreen.main.bounds.height * 0.2)

                VStack(spacing: 20.0) {
                    modeTypeView(of: .silent)
                    modeTypeView(of: .doNotDisturb)
                }
                .padding(.vertical, 61.0)
            }

            Image(type.iconResourceName)
                .padding(.vertical, 16.0)

            Text(type.description)
                .highlighted(
                    wholeText: type.description,
                    highlightText: type.highlightTextOnDescription,
                    normalColor: .white,
                    highlightColor: .orange500
                )
                .pretendardFont(weight: .semiBold600, size: 20.0)
                .multilineTextAlignment(.center)
                .fixedSize(horizontal: false, vertical: true)

            if let subDescription = type.subDescription {
                Text(subDescription)
                    .pretendardFont(weight: .medium500, size: 14.0)
                    .foregroundStyle(.white)
                    .padding(.top, 12.0)
            }

            Spacer()

            if type.hasSkipButton {
                CTAButton(
                    text: "건너뛰기",
                    textFont: .pretendard(.medium500, size: 16.0),
                    type: .white
                ) {
                    store.send(.skipButtonTapped)
                }
                .padding(.bottom, 12.0)
            }

            CTAButton(text: type.confirmButtonTitle, type: .orange) {
                store.send(.confirmButtonTapped)
            }
            .padding(.bottom, 20.0)
            .padding(.horizontal, 20.0)
        }
    }

    func modeTypeView(of type: ModeType) -> some View {
        HStack(spacing: 12.0) {
            type.icon

            Text(type.text)
                .pretendardFont(weight: .medium500, size: 16.0)
                .foregroundStyle(.coolGray900)
                .frame(maxWidth: .greatestFiniteMagnitude, alignment: .leading)

            Image(.imageToggleSwitch)
        }
        .padding(.horizontal, 16.0)
        .padding(.vertical, 12.0)
        .background(Color.coolGray25)
        .clipShape(
            RoundedRectangle(cornerRadius: 15.0)
        )
        .overlay {
            RoundedRectangle(cornerRadius: 15.0)
                .stroke(Color.coolGray75, lineWidth: 1.0)
        }
        .padding(.horizontal, 48.0)
    }

    var snapshotStartAlertView: some View {
        VStack(spacing: 0) {
            VStack(alignment: .leading, spacing: 4) {
                Text("인증샷을 찍어 \n친구들에게 자랑해볼까요?")
                    .pretendardFont(weight: .semiBold600, size: 20)
                    .foregroundColor(.coolGray900)

                Text("인증샷은 지금 남기지 않으면 사라져요")
                    .pretendardFont(weight: .medium500, size: 16)
                    .foregroundColor(.gray600)
            }
            .frame(maxWidth: .greatestFiniteMagnitude, alignment: .leading)
            .padding(.bottom, 26)

            Image(.imageSummaryCardBottomsheet)
                .resizable()
                .aspectRatio(contentMode: .fit)
                .frame(height: 205)
                .padding(.bottom, 24)

            HStack(spacing: 8) {
                CTAButton(text: "안할래요", type: .gray) { store.send(.snapshotStartAlertTapped(false))
                }

                CTAButton(text: "인증샷 찍기", type: .dark) {
                    store.send(.snapshotStartAlertTapped(true))
                }
            }
        }
    }

    func snapshotTypeAlertView() -> some View {
        let components: [SnapshotType] = [.camera, .gallery, .card]

        return VStack(alignment: .leading, spacing: 0) {
            Text("어떤 방식으로 인증할까요?")
                .foregroundStyle(.coolGray900)
                .pretendardFont(weight: .semiBold600, size: 20)
                .padding(.bottom, 24)

            VStack(spacing: 8) {
                ForEach(0..<components.count, id: \.self) { idx in
                    WithPerceptionTracking {
                        HStack(spacing: 0) {
                            Image(components[idx].imageResource)
                                .resizable()
                                .frame(width: 20, height: 20)
                                .padding(.trailing, 12)

                            Text(components[idx].title)
                                .foregroundStyle(.coolGray800)
                                .pretendardFont(weight: .semiBold600, size: 16)

                            Spacer()

                            if store.snapshotType == components[idx] {
                                Image(.imageCheck)
                                    .resizable()
                                    .frame(width: 24, height: 24)
                            }

                        }
                        .frame(height: 52, alignment: .leading)
                        .frame(maxWidth: .greatestFiniteMagnitude)
                        .padding(.horizontal, 16)
                        .background(store.snapshotType == components[idx] ? .coolGray50 : .white)
                        .cornerRadius(15)
                        .onTapGesture {
                            store.send(.snapshotTypeTapped(components[idx]))
                        }
                    }
                }
            }
        }
        .background(.white)
    }

    enum ModeType {
        case silent
        case doNotDisturb

        var icon: Image {
            switch self {
            case .silent:
                Image(.imageNotificationFill)
            case .doNotDisturb:
                Image(.imageMoonClearFill)
            }
        }

        var text: String {
            switch self {
            case .silent:
                "무음모드"
            case .doNotDisturb:
                "방해금지 모드"
            }
        }
    }
}

struct TagListView: View {
    private struct Constants {
        static let textFont: Font = .pretendard(.semiBold600, size: 16)
        static let textColor: Color = .coolGray900
        static let backgroundColor: Color = .coolGray75
        static let cornerRadius = 10.0
