import ComposableArchitecture
import Foundation

@Reducer
struct MainFeature {
    @ObservableState
    struct State: Equatable {
        var path = StackState<Path.State>()
        @Presents var destination: Destination.State?

        var currentIndex: Int = .zero
        var selectorViewOffset: CGFloat = .zero
        var toast: Toast?
        var isAvatarTapped: Bool = false
        var currentGuideType: GuideType = .previewOnTouch
        var showGuide: Bool = true
        var showSnapshotAlert: Bool = false
        var showSnapshotTypeAlert: Bool = false
        var snapshotType: SnapshotType? = nil
        var snapshotBackAlertShown: Bool = false
    }

    enum Action: BindableAction {
        // 화면 이동
        case path(StackAction<Path.State, Path.Action>)
        case destination(PresentationAction<Destination.Action>)

        // 가이드 화면
        case skipButtonTapped
        case confirmButtonTapped

        // 메인 화면
        case avatarTapped
        case avatarTapStateChanged
        case avatarSelectorDragChanged(CGFloat)
        case avatarSelectorDragEnded(Int)
        case avatarSelectorDotTapped(Int)
        case timerSettingButtonTapped
        case appSettingButtonTapped
        case snapshotStartAlertTapped(Bool)
        case snapshotTypeTapped(SnapshotType)
        case snapshotPathBecameEmpty
        case onLoad
        case binding(BindingAction<State>)
    }

    @Dependency(\.notificationManager) private var notificationManager
    @Dependency(\.timerSettingManager) private var timerSettingManager
    @Dependency(\.userDefaults) private var userDefaults
    @Dependency(\.voiceManager) private var voiceManager

    var body: some ReducerOf<Self> {
        BindingReducer()
        Reduce<State, Action> { state, action in
            switch action {
            case .onLoad:
                guard userDefaults.guideRequired == false else {
                    state.showGuide = true
                    return .none
                }

                state.showGuide = false
                notificationManager.requestPermission() // 푸시 권한 요청

                guard let existingTimer = timerSettingManager.getTimer() else {
                    return .none
                }

                if existingTimer.leftTime > .zero {
                    state.destination = .timerOnProgress(.init(timer: existingTimer))
                } else {
                    state.destination = .timerEnd(.init(timer: existingTimer))
                }

                return .none

            // 가이드
            case .skipButtonTapped:
                return guideCompleted(state: &state)

            case .confirmButtonTapped:
                if let currentIndex = GuideType.allCases.firstIndex(of: state.currentGuideType),
                   let nextGuideType = GuideType.allCases[safe: currentIndex + 1] {
                    state.currentGuideType = nextGuideType
                    return .none
                } else {
                    return guideCompleted(state: &state)
                }

            // 메인
            case .avatarTapped:
                state.isAvatarTapped.toggle()

                return .run { send in
                    try await Task.sleep(nanoseconds: 100_000_000)
                    await send(.avatarTapStateChanged)
                }

            case .avatarTapStateChanged:
                let currentAvatar = AvatarType.allCases[state.currentIndex]

                voiceManager.playOrStopPreview(with: currentAvatar.timerPreviewVoiceName)

                if voiceManager.isPreviewMuted {
                    state.toast = Toast(
                        image: "image_toast_volume",
                        message: "\(currentAvatar.name)가 말 하고 있어요. 볼륨을 켜주세요."
                    )
                }

                state.isAvatarTapped.toggle()
                return .none

            case let .avatarSelectorDragChanged(translatedValue):
                state.selectorViewOffset = translatedValue
                return .none

            case let .avatarSelectorDragEnded(changedIndex):
                state.selectorViewOffset = 0
                return selectedIndexChanged(state: &state, newIndex: changedIndex)

            case let .avatarSelectorDotTapped(changedIndex):
                return selectedIndexChanged(state: &state, newIndex: changedIndex)

            case .timerSettingButtonTapped:
                voiceManager.stopPlayingPreview()
                state.toast = nil
                state.path.append(.timerSetting(.init()))
                return .none

            case .appSettingButtonTapped:
                state.toast = nil
                state.path.append(.appSetting(.init()))
                return .none
            case let .snapshotStartAlertTapped(start):
                state.showSnapshotAlert = false

                if start {
                    state.snapshotType = nil
                    state.showSnapshotTypeAlert = true
                }
                return .none

            case let .snapshotTypeTapped(snapshotType):
                state.snapshotType = snapshotType
                state.showSnapshotTypeAlert = false

                switch snapshotType {
                case .camera:
                    state.path.append(.camera(.init()))
                case .gallery:
                    state.path.append(.gallery(.init()))
                case .card:
                    state.path.append(.summaryCard(.init()))
                }
                return .none

            case let .path(.element(id: _, action: .timerSetting(.setupTimer(timer)))):
                timerSettingManager.saveTimerAndSchedulePush(timer)
                state.destination = .timerOnProgress(.init(timer: timer))

                // 타이머 진행중 화면에 토스트 메세지 전달
                return .send(.destination(.presented(.timerOnProgress(.timerSetCompleted(toastMessage: toastMessage(of: timer))))))

            case let .destination(.presented(.timerOnProgress(.delegate(.timerFinished(timer))))):
                state.destination = .timerEnd(.init(timer: timer))
                return .none

            case let .destination(.presented(.timerEnd(.delegate(.timerTurnedOff(mode))))):
                state.destination = nil

                switch mode {
                case .focus:
                    state.showSnapshotAlert = true
                    state.snapshotBackAlertShown = false
                case .rest:
                    state.toast = Toast(
                        image: "image_toast_kiki",
                        message: "쉬는 시간 끝! 이제 멋지게 시작해볼까요?"
                    )
                }
                return .none

            case let .destination(.presented(.timerEnd(.delegate(.startNewTimer(timer))))):
                state.destination = .timerOnProgress(.init(timer: timer))
                return .none

            case let .path(.element(id: _, action: .camera(.onPhotoCaptured(photo)))):
                state.path.append(.snapshotEdit(.init(image: photo)))
                return .none
            case let .path(.element(id: _, action: .gallery(.onPhotoSelected(photo)))):
                state.path.append(.snapshotEdit(.init(image: photo)))
                return .none
            case let .path(.element(id: _, action: .snapshotEdit(.onImageRendered(uiImage)))):
                state.path.append(.snapshotShare(.init(image: uiImage)))
                return .none
            case .path(.element(id: _, action: .snapshotShare(.onCloseButtonTapped))):
                state.path.removeAll()
                state.snapshotType = nil
                return .none

            case .snapshotPathBecameEmpty:
                guard state.snapshotType != nil, !state.snapshotBackAlertShown else { return .none }
                state.snapshotType = nil
                state.snapshotBackAlertShown = true
                state.showSnapshotAlert = true
                return .none
            default:
                return .none
            }
        }
        .ifLet(\.$destination, action: \.destination)
        .forEach(\.path, action: \.path)
    }
}

extension MainFeature {
    @Reducer
    enum Path {
        case timerSetting(TimerSettingFeature)
        case appSetting(AppSettingFeature)
        case statistics(StatisticsFeature)
        case camera(CameraFeature)
        case gallery(GalleryFeature)
        case snapshotEdit(SnapshotEditFeature)
        case snapshotShare(SnapshotShareFeature)
        case summaryCard(SummaryCardFeature)
    }

    @Reducer
    enum Destination {
        case timerOnProgress(TimerOnProgressFeature)
        case timerEnd(TimerEndFeature)
    }

    enum GuideType: Int, CaseIterable {
        case previewOnTouch
        case turnOffSilentMode

        var iconResourceName: String {
            switch self {
            case .previewOnTouch:
                "image_click"
            case .turnOffSilentMode:
                "image_notification"
            }
        }

        var description: String {
            switch self {
            case .previewOnTouch:
                "캐릭터를 터치하면\n목소리를 들을 수 있어요"
            case .turnOffSilentMode:
                "무음 모드를 해제해주세요."
            }
        }

        var highlightTextOnDescription: String? {
            switch self {
            case .previewOnTouch:
                "캐릭터를 터치"
            case .turnOffSilentMode:
                "무음 모드"
            }
        }

        var subDescription: String? {
            switch self {
            case .previewOnTouch:
                nil
            case .turnOffSilentMode:
                "시스템 볼륨을 꺼두면 타이머 알림이 들리지 않아요."
            }
        }

        var hasSkipButton: Bool {
            switch self {
            case .previewOnTouch: true
            case .turnOffSilentMode: false
            }
        }

        var confirmButtonTitle: String {
            switch self {
            case .previewOnTouch:
                "다음"
            case .turnOffSilentMode:
                "확인"
            }
        }
    }
}

private extension MainFeature {
    func toastMessage(of timer: TimerEntity) -> String {
        return "\(timer.avatar.name)가 \(formattedDuration(of: timer.duration)) 뒤에 알려줄게!"
    }

    func formattedDuration(of duration: TimeInterval) -> String {
        let totalMinutes = Int(duration / 60)
        let hours = totalMinutes / 60
        let remainingMinutes = totalMinutes % 60

        switch (hours, remainingMinutes) {
        case let (h, m) where h > 0 && m > 0:
            return String(format: "%d시간 %d분", h, m)
        case let (h, _) where h > 0:
            return String(format: "%d시간", h)
        case let (_, m) where m > 0:
            return String(format: "%d분", m)
        default:
            return "\(remainingMinutes)분"
        }
    }

    func selectedIndexChanged(
        state: inout State,
        newIndex: Int
    ) -> Effect<Action> {
        state.currentIndex = newIndex
        voiceManager.stopPlayingPreview()

        return .none
    }

    func guideCompleted(state: inout State) -> Effect<Action> {
        state.showGuide = false
        userDefaults.setGuideCompleted()
        notificationManager.requestPermission() // 푸시 권한 요청

        return .none
    }
}

