import SwiftUI

import ComposableArchitecture

struct MainView: View {
    private struct Constants {
        static let buttonString = "%@랑 타이머 설정하기"
        static let backgroundColor: Color = .coolGray25
        static let guideBackgroundColor: Color = .black.opacity(0.8)
        static let avatarHighlightSize: CGFloat = 240.0
    }

