import SwiftUI

import ComposableArchitecture

struct MainView: View {
    private struct Constants {
        static let buttonString = "%@랑 타이머 설정하기"
        static let backgroundColor: Color = .coolGray25
        static let guideBackgroundColor: Color = .black.opacity(0.8)
        static let avatarHighlightSize: CGFloat = 240.0
    }

    @Perception.Bindable private var store: StoreOf<MainFeature>
    @State private var commonTitleButtonTopOffset: CGFloat = .zero
    @State private var avatarScrollViewBottomYOffset: CGFloat = .zero

    init(store: StoreOf<MainFeature>) {
        self.store = store
    }

    var body: some View {
        WithPerceptionTracking {
            NavigationStack(
                path: $store.scope(state: \.path, action: \.path)
            ) {
                VStack(spacing: 0) {
                    titleAndSettingButtonView

                    AvatarBubbleView(text: store.currentAvatarType.mainMessage)
                        .padding(.bottom, 23)
                        .padding(.horizontal, 20)
                        .dimmedIfNeeded(
                            shouldDimmed: store.showGuide,
                            shouldHighlight: store.currentGuideType == .previewOnTouch
                        )

                    avatarSelectorView

                    AvatarNameView(text: "\(store.currentAvatarType.englishName) \(store.currentAvatarType.name)")
                        .padding(.bottom, 16)
                        .dimmedIfNeeded(shouldDimmed: store.showGuide)

                    TagListView(avatarType: store.currentAvatarType)
                        .padding(.horizontal, 20)
                        .padding(.bottom, 44)
                        .dimmedIfNeeded(shouldDimmed: store.showGuide)

                    DotSelectorView(count: store.avatarList.count, currentIndex: store.currentIndex) { idx in
                        store.send(.avatarSelectorDotTapped(idx))
                    }
                    .dimmedIfNeeded(shouldDimmed: store.showGuide)

                    Spacer()
                        .frame(minHeight: 73.0)
                        .dimmedIfNeeded(shouldDimmed: store.showGuide)

                    CTAButton(text: String(format: Constants.buttonString, store.currentAvatarType.name), type: .dark) {
                        store.send(.timerSettingButtonTapped)
                    }
                    .padding(.bottom, 20)
                    .padding(.horizontal, 20)
                    .dimmedIfNeeded(shouldDimmed: store.showGuide)
                }
                .wrapScrollIfNeeded()
                .disabled(store.showGuide)
                .background(Constants.backgroundColor)
                .overlay {
                    if store.showGuide {
                        guideView
                    }
                }

            } destination: { childStore in
                WithPerceptionTracking {
                    switch childStore.state {
                    case .timerSetting:
                        if let childStore = childStore.scope(
                            state: \.timerSetting,
                            action: \.timerSetting
                        ) {
                            TimerSettingView(store: childStore, avatarType: store.currentAvatarType)
                        }

                    case .appSetting:
                        if let childStore = childStore.scope(
                            state: \.appSetting,
                            action: \.appSetting
                        ) {
                            AppSettingView(store: childStore)
                        }

                    case .statistics:
                        if let childStore = childStore.scope(
                            state: \.statistics,
                            action: \.statistics
                        ) {
                            StatisticsView(store: childStore)
                        }

                    case .camera:
                        if let childStore = childStore.scope(
                            state: \.camera,
                            action: \.camera
                        ) {
                            CameraView(store: childStore)
                        }

                    case .gallery:
                        if let childStore = childStore.scope(
                            state: \.gallery,
                            action: \.gallery
                        ) {
                            GalleryView(store: childStore)
                        }

                    case .snapshotEdit:
                        if let childStore = childStore.scope(
                            state: \.snapshotEdit,
                            action: \.snapshotEdit
                        ) {
                            SnapshotEditView(store: childStore)
                        }
                    case .snapshotShare:
                        if let childStore = childStore.scope(
                            state: \.snapshotShare,
                            action: \.snapshotShare
                        ) {
                            SnapshotShareView(store: childStore)
                        }
                    case .summaryCard:
                        if let childStore = childStore.scope(
                            state: \.summaryCard,
                            action: \.summaryCard
                        ) {
                            SummaryCardView(store: childStore)
                        }
                    }
                }
            }
            .fullScreenCover(
                item: $store.scope(
                    state: \.destination?.timerOnProgress,
                    action: \.destination.timerOnProgress
                ),
                content: { store in
                    TimerOnProgressView(store: store)
                }
            )
            .fullScreenCover(
                item: $store.scope(
                    state: \.destination?.timerEnd,
                    action: \.destination.timerEnd
                ),
                content: { store in
                    TimerEndView(store: store)
                }
            )
            .onLoad {
                store.send(.onLoad)
            }
            .onChange(of: store.path.isEmpty) { isEmpty in
                if isEmpty {
                    store.send(.snapshotPathBecameEmpty)
                }
            }
            .toast(
                toast: $store.toast,
                hasCTAButton: true
            )
            .customAlert(isPresented: $store.showSnapshotAlert) {
                snapshotStartAlertView
            }
            .customAlert(isPresented: $store.showSnapshotTypeAlert) {
                snapshotTypeAlertView()
            }
        }
    }
}

