                    .padding(.bottom, 58)
            }
        }
        .background(
            GeometryReader(content: { proxy in
                Color.clear
                    .onLoad {
                        commonTitleButtonTopOffset = proxy.frame(in: .global).minY
                    }
            })
        )
    }

    @ViewBuilder
    var avatarSelectorView: some View {
        if store.showGuide {
            ZStack {
                if store.currentGuideType == .previewOnTouch {
                    Constants.guideBackgroundColor

                    RoundedRectangle(cornerRadius: 30.0)
                        .fill(Constants.backgroundColor)
                        .frame(width: Constants.avatarHighlightSize, height: Constants.avatarHighlightSize)

                    RoundedRectangle(cornerRadius: 30.0)
                        .stroke(
                            .orange400,
                            style: StrokeStyle(
                                lineWidth: 3.0,
                                lineCap: .round,
                                dash: [14, 8]
                            )
                        )
                        .frame(width: Constants.avatarHighlightSize, height: Constants.avatarHighlightSize)
                }

                avatarScrollView
                    .dimmedIfNeeded(shouldDimmed: store.currentGuideType != .previewOnTouch)
                    .disabled(true)
            }
            .zIndex(1)
        } else {
            avatarScrollView
        }
    }

    var avatarScrollView: some View {
        struct Constants {
            static let itemWidth: CGFloat = 240
            static let itemHeight: CGFloat = 240
            static let screenWidth: CGFloat = UIScreen.main.bounds.width
            static let spacing: CGFloat = (Constants.screenWidth - Constants.itemWidth * 1.5)/2
        }

        return ScrollView(.horizontal) {
            HStack(spacing: Constants.spacing) {
                    Color.clear
                    .frame(width: (Constants.screenWidth - Constants.itemWidth)/2 - Constants.spacing)

                ForEach(0..<store.avatarImages.count, id: \.self) { idx in
                    WithPerceptionTracking {
                        Button {
                            store.send(.avatarTapped)
                        } label: {
                            store.avatarImages[idx]
                                .resizable()
                                .frame(width: Constants.itemWidth)
                                .scaleEffect(store.isAvatarTapped && store.currentIndex == idx ? 0.9 : 1.0)
                                .animation(.linear(duration: 0.2), value: store.isAvatarTapped)
                        }
                    }
                }
            }
            .offset(x: CGFloat(-(store.currentIndex)) * (Constants.itemWidth + Constants.spacing) + store.selectorViewOffset)
                .animation(.easeOut, value: store.currentIndex)
                .highPriorityGesture(
                    DragGesture()
                        .onChanged { value in
                            store.send(.avatarSelectorDragChanged(min(value.translation.width, Constants.itemWidth + Constants.spacing)))
                        }
                        .onEnded { value in
                            var newIdx = store.currentIndex
                            newIdx -= Int(value.predictedEndTranslation.width) > 0 ? 1 : -1
                            newIdx = max(0, min(newIdx, store.avatarImages.count-1))

                            store.send(.avatarSelectorDragEnded(newIdx))
                        }
                )
            .frame(height: Constants.itemHeight)
        }
        .scrollDisabled(true)
        .background(
            GeometryReader(content: { proxy in
                Color.clear
                    .onLoad {
                        avatarScrollViewBottomYOffset = proxy.frame(in: .global).maxY
                    }
            })
        )
    }
}

