                            action: \.statistics
                        ) {
                            StatisticsView(store: childStore)
                        }

                    case .camera:
                        if let childStore = childStore.scope(
                            state: \.camera,
                            action: \.camera
                        ) {
                            CameraView(store: childStore)
                        }

                    case .gallery:
                        if let childStore = childStore.scope(
                            state: \.gallery,
                            action: \.gallery
                        ) {
                            GalleryView(store: childStore)
                        }

                    case .snapshotEdit:
                        if let childStore = childStore.scope(
                            state: \.snapshotEdit,
                            action: \.snapshotEdit
                        ) {
                            SnapshotEditView(store: childStore)
                        }
                    case .snapshotShare:
                        if let childStore = childStore.scope(
                            state: \.snapshotShare,
                            action: \.snapshotShare
                        ) {
                            SnapshotShareView(store: childStore)
                        }
                    case .summaryCard:
                        if let childStore = childStore.scope(
                            state: \.summaryCard,
                            action: \.summaryCard
                        ) {
                            SummaryCardView(store: childStore)
                        }
                    }
                }
            }
            .fullScreenCover(
                item: $store.scope(
                    state: \.destination?.timerOnProgress,
                    action: \.destination.timerOnProgress
                ),
                content: { store in
                    TimerOnProgressView(store: store)
                }
            )
            .fullScreenCover(
                item: $store.scope(
                    state: \.destination?.timerEnd,
                    action: \.destination.timerEnd
                ),
                content: { store in
                    TimerEndView(store: store)
                }
            )
            .onLoad {
                store.send(.onLoad)
            }
            .onChange(of: store.path.isEmpty) { isEmpty in
                if isEmpty {
                    store.send(.snapshotPathBecameEmpty)
                }
            }
            .toast(
                toast: $store.toast,
                hasCTAButton: true
            )
            .customAlert(isPresented: $store.showSnapshotAlert) {
                snapshotStartAlertView
            }
            .customAlert(isPresented: $store.showSnapshotTypeAlert) {
                snapshotTypeAlertView()
            }
        }
    }
}

