            }

            Image(type.iconResourceName)
                .padding(.vertical, 16.0)

            Text(type.description)
                .highlighted(
                    wholeText: type.description,
                    highlightText: type.highlightTextOnDescription,
                    normalColor: .white,
                    highlightColor: .orange500
                )
                .pretendardFont(weight: .semiBold600, size: 20.0)
                .multilineTextAlignment(.center)
                .fixedSize(horizontal: false, vertical: true)

            if let subDescription = type.subDescription {
