import Foundation

struct TimerEntity: Codable, Equatable {
    let avatar: AvatarType
    let startTime: Date
    let duration: TimeInterval
    var timerEndName: String // 타이머 종료 화면의 음성파일/텍스트 이름
    let mode: TimerMode
    var leftTime: TimeInterval // 남은 시간
    var status: Status = .running
    var lastUpdatedAt: Date // 마지막으로 leftTime을 갱신한 기준 시각

    enum Status: Codable, Equatable {
        case running, paused
    }

    init(
        avatar: AvatarType,
        startTime: Date,
        duration: TimeInterval,
        timerEndName: String,
        mode: TimerMode,
        now: Date = .now
    ) {
        self.avatar = avatar
        self.startTime = startTime
        self.duration = duration
        self.timerEndName = timerEndName
        self.mode = mode

        let initialLeft = max(.zero, duration - now.timeIntervalSince(startTime))
        self.leftTime = initialLeft
        self.lastUpdatedAt = now
    }

    mutating func tick(now: Date = .now) {
        guard status == .running else {
            lastUpdatedAt = now // 시계 기준점만 갱신
            return
        }
        let delta = now.timeIntervalSince(lastUpdatedAt) // 마지막 갱신 이후 실제로 흐른 시간(초)
        if delta > .zero {
            leftTime = max(.zero, leftTime - delta)
            lastUpdatedAt = now
        }
    }

    mutating func pause(now: Date = .now) {
        tick(now: now)
        status = .paused
    }

    mutating func resume(now: Date = .now) {
        lastUpdatedAt = now
        status = .running
    }
}

