//
//  UserDefaultsClient.swift
//  ggaebiz
//
//  Created by mirim.kim on 1/28/25.
//

import Dependencies
import Foundation

final class UserDefaultsClient {

    @propertyWrapper
    private struct UserDefault<T: Codable> {
        let key: String
        let userDefaults: UserDefaults

        init(
            key: String,
            userDefaults: UserDefaults = .standard
        ) {
            self.key = key
            self.userDefaults = userDefaults
        }

        var wrappedValue: T? {
            get {
                if let savedData = userDefaults.object(forKey: key) as? Data {
                    if let decodedObject = try? JSONDecoder().decode(T.self, from: savedData) {
                        return decodedObject
                    }
                }

                return nil
            }
            set {
                if let encodedData = try? JSONEncoder().encode(newValue) {
                    userDefaults.set(encodedData, forKey: key)
                }
            }
        }
    }

    @UserDefault(key: "guideRequired")
    private var appGuideRequired: Bool?

    var guideRequired: Bool {
        return appGuideRequired ?? true
    }

    func setGuideCompleted() {
        appGuideRequired = false
    }

    @UserDefault(key: "timer")
    private var timer: TimerEntity?

    func getTimer() -> TimerEntity? {
        return timer
    }

    func setTimer(_ newTimer: TimerEntity) {
        timer = newTimer
    }

    func removeTimer() {
        timer = nil
    }

    @UserDefault(key: "settingSliderScale") // 앱 설정 슬라이드값
    private var settingSliderScale: [SettingType: Float]?

    func getSettingSliderScale(for type: SettingType) -> Float {
        return settingSliderScale?[type] ?? 0.5
    }

    func setSettingSliderScale(for type: SettingType, value: Float) {
        if settingSliderScale == nil {
            settingSliderScale = [:]
        }

        settingSliderScale?[type] = value
    }

    @UserDefault(key: "settingToggleValue") // 앱 설정 토글 값
    private var settingToggleValue: [SettingType: Bool]?

    func isSettingToggleOn(for type: SettingType) -> Bool {
        return settingToggleValue?[type] ?? true
    }

    func setSettingToggle(for type: SettingType, to value: Bool) {
        if settingToggleValue == nil {
            settingToggleValue = [:]
        }

        settingToggleValue?[type] = value
    }

    @UserDefault(key: "useTooltip") // 툴팁 노출 여부
    private var useTooltip: [TooltipType: Bool]?

    func canUseTooltip(for type: TooltipType) -> Bool {
        return useTooltip?[type] ?? true
    }

    func setCanUseTooltip(for type: TooltipType, _ newValue: Bool) {
        if useTooltip == nil {
            useTooltip = [:]
        }

        useTooltip?[type] = newValue
    }

    @UserDefault(key: "needsOnboarding") // 앱 설정 토글 값
    private var onboardingRequired: Bool?

    func needsOnboarding() -> Bool {
        return onboardingRequired ?? true
    }

    func setOnboardingCompleted() {
        onboardingRequired = false
    }

    @UserDefault(key: "snapshotTimer") // 인증샷 기능을 위한 타이머
    private var timerForSnapshot: TimerEntity?

    var snapshotTimer: TimerEntity? {
        return timerForSnapshot
    }

    func setSnapshotTimer(_ timer: TimerEntity) {
        timerForSnapshot = timer
    }
}

extension UserDefaultsClient: DependencyKey {
    static let liveValue = UserDefaultsClient()
}

extension DependencyValues {
    var userDefaults: UserDefaultsClient {
        get { self[UserDefaultsClient.self] }
        set { self[UserDefaultsClient.self] = newValue }
    }
}

